// 1. Get incoming webhook items
const item = $input.item.json;

// 2. Extract variables safely with proper fallbacks
const userMessage = item.userMessage || item.message || (item.article ? "Summarize this article and send to my email" : "");
const userContent = item.userContent || item.article || "";
const conversationHistory = item.conversationHistory || [];
const requestBody = item || {};
const userEmail = requestBody.email || requestBody.email_to || 'faisalmrasul13@gmail.com';
const sessionId = requestBody.sessionId || requestBody.session_id || 'session_' + Math.random().toString(36).substr(2, 9);
// 2. Validate required fields (using standard n8n error handling or fallback)
if (!userMessage || userMessage.trim() === '') {
    throw new Error('Message field is required');
}

// 3. Process the history array safely
const trimmedHistory = Array.isArray(conversationHistory) ? conversationHistory.slice(-10) : [];

// 4. Construct the output object
const outputData = {
    userMessage: userMessage,
    userContent: userContent,
    sessionId: sessionId,
    userEmail: userEmail,
    conversationHistory: trimmedHistory,
    timestamp: new Date().toISOString(),
    requestId: `req_${Date.now()}_${Math.floor(Math.random() * 1000000)}`
};

// 5. Return the array of objects for n8n
return [{ json: outputData }];

const data = $input.first().json;

const wordCount = data.userMessage.split(' ').length;
const hasContent = data.userContent && data.userContent.length > 0;
const complexity = wordCount > 50 ? 'high' : wordCount > 20 ? 'medium' : 'low';

const needsMultiStep = data.userMessage.toLowerCase().includes('compare') ||
                      data.userMessage.toLowerCase().includes('analyze') ||
                      data.userMessage.toLowerCase().includes('research') ||
                      wordCount > 100;

const executionPlan = {
  complexity: complexity,
  needsMultiStep: needsMultiStep,
  estimatedTokens: hasContent ? data.userContent.length / 4 : 500,
  steps: needsMultiStep ? ['analyze', 'generate', 'validate'] : ['process']
};

return [{
  json: {
    ...data,
    complexity,
    needsMultiStep,
    executionPlan,
    agentState: 'planning_complete'
  }
}];

