// Get the incoming item from the Intelligent Agent Router
const incomingItem = $input.item;

try {
  // Extract the stringified JSON from Groq's response structure
  const rawContent = incomingItem.json.choices[0].message.content;

  // Parse it into a real JavaScript object
  const parsedData = JSON.parse(rawContent);

  // Return the data cleanly for downstream nodes
  return {
    json: {
      agent_target: parsedData.agent_target,
      agent_name: parsedData.agent_name,
      // Pass along the initial user info so it isn't lost
      userMessage: $('Agentic Planning Layer').item.json.userMessage,
      userEmail: $('Agentic Planning Layer').item.json.userEmail
    }
  };

} catch (error) {
  // Fallback if parsing fails for any reason
  return {
    json: {
      agent_target: "clarification",
      agent_name: "Clarification Agent",
      error: "Failed to parse router decision: " + error.message
    }
  };
}

