const data = $input.first().json;
const clarifyMessage = `I need a bit more information to help you best:

Please clarify:
1. What would you like me to do? (summarize / create post / improve / research / analyze)
2. Do you have content to share?
3. Any platform preference? (LinkedIn, Twitter, Instagram, Email)

Example: "Summarize this article about AI" or "Write a LinkedIn post about remote work"`;

return [{
  json: {
    ...data,
    agent_response: clarifyMessage,
    tool_used: 'CLARIFICATION'
  }
}];

// ==========================================
// 1. EXTRACT DATA & CREATE CONTEXT FALLBACKS
// ==========================================
// Safely fetch data from the Decision Layer
let ctx = {};
try {
  ctx = $('Parse Agent Decision').first().json || {};
} catch (e) {
  ctx = {};
}

// Safely pull routing variables
const tool = ctx.tool || 'SUMMARIZE';

const toolNodeMap = {
  SUMMARIZE: 'Summarization Agent',
  GENERATE_POST: 'Content Creation Agent',
  IMPROVE: 'Content Improvement Agent',
  RESEARCH: 'Research Agent',
  ANALYZE: 'Analytics Agent',
  ANSWER: 'General Assistant Agent',
  CLARIFY: 'Clarification Agent'
};

let agentOutput = '';
let agentError = false;

// ==========================================
// 2. AGENT ROUTING & RESPONSE EXTRACTION
// ==========================================
if (tool === 'CLARIFY') {
  try {
    const clarifyData = $('Clarification Agent').first().json;
    agentOutput = clarifyData.agent_response || clarifyData.output || '';
  } catch(e) {
    agentOutput = 'Please provide more details so I can help you better.';
  }
} else {
  const nodeName = toolNodeMap[tool] || 'Summarization Agent';
  try {
    const nodeData = $(nodeName).first().json;
    if (nodeData.error) {
      agentOutput = `Error with ${tool} agent: ${nodeData.error.message || 'Unknown error'}. Please try again.`;
      agentError = true;
    } else {
      // Safely checks Groq choices format, falling back to a direct text response property
      agentOutput = nodeData.choices?.[0]?.message?.content || nodeData.agent_response || nodeData.output || 'No response generated.';
    }
  } catch(e) {
    agentOutput = 'An unexpected error occurred while compiling the agent summary. Please try again.';
    agentError = true;
  }
}

// ==========================================
// 3. SECURE DISPLAY VARIABLES (NO MORE UNDEFINED)
// ==========================================
const displayAgentName = toolNodeMap[tool] || 'Summarization Agent';
const displayPlatform = ctx.platform || 'General AI Pipeline';
const displayConfidence = ctx.confidence || '100';
const displaySessionId = ctx.sessionId || ctx.session_id || 'session_active';
const displayTone = ctx.tone || 'Professional';
const displayReasoning = ctx.reasoning || 'Direct processing';
const displayUserMessage = ctx.userMessage || 'Summarize this article';
const displayUserEmail = ctx.userEmail || 'faisalmrasul13@gmail.com';

// ==========================================
// 4. GENERATE RICH HTML EMAIL TEMPLATE
// ==========================================
const htmlEmail = `<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"><title>AI Agent Response</title>
<style>
body { font-family: Arial, sans-serif; line-height: 1.6; padding: 20px; max-width: 700px; margin: auto; }
.header { background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); color: white; padding: 30px; text-align: center; border-radius: 10px 10px 0 0; }
.content { background: #f7f9fc; padding: 30px; border-radius: 0 0 10px 10px; }
.agent-info { background: white; padding: 20px; border-radius: 10px; margin-bottom: 20px; border-left: 4px solid #667eea; }
.response { background: white; padding: 20px; border-radius: 10px; white-space: pre-wrap; }
.confidence-bar { background: #e2e8f0; height: 8px; border-radius: 4px; margin-top: 5px; }
.confidence-fill { background: #48bb78; height: 100%; width: ${displayConfidence}%; border-radius: 4px; }
</style>
</head>
<body>
<div class="header">
<h1>🤖 Advanced AI Agent</h1>
<p>Your intelligent content assistant</p>
</div>
<div class="content">
<div class="agent-info">
<p><strong>🎯 Agent Used:</strong> ${displayAgentName}</p>
<p><strong>📱 Platform:</strong> ${displayPlatform}</p>
<p><strong>🎨 Tone:</strong> ${displayTone}</p>
<p><strong>📊 Confidence:</strong> ${displayConfidence}%</p>
<div class="confidence-bar"><div class="confidence-fill"></div></div>
<p><strong>💭 Reasoning:</strong> ${displayReasoning}</p>
<p><strong>🆔 Session:</strong> ${displaySessionId}</p>
</div>
<h2>📄 Response</h2>
<div class="response">${agentOutput.replace(/\n/g, '<br>')}</div>
<p style="margin-top: 20px; font-size: 12px; color: #666;">Generated by Advanced AI Agent v4.0 | Powered by Groq</p>
</div>
</body>
</html>`;

// ==========================================
// 5. GENERATE CLEAN PLAIN TEXT EMAIL TEMPLATE
// ==========================================
const plainTextEmail = `ADVANCED AI AGENT RESPONSE
===========================================
Agent: ${displayAgentName}
Platform: ${displayPlatform}
Confidence: ${displayConfidence}%
Session: ${displaySessionId}

RESPONSE:
${agentOutput}

---
Your request: ${displayUserMessage}`;

// ==========================================
// 6. RETURN UNIFIED DATA TO GMAIL NODE
// ==========================================
return [{
    json: {
        success: !agentError,
        agent_response: agentOutput,
        output: agentOutput, 
        agent_name: displayAgentName,
        platform: displayPlatform,
        confidence: displayConfidence,
        session_id: displaySessionId,
        session: displaySessionId,
        tool_used: tool,
        reasoning: displayReasoning,
        tone: displayTone,
        userEmail: displayUserEmail,
        userMessage: displayUserMessage,
        timestamp: new Date().toISOString(),
        htmlEmail: htmlEmail,
        plainTextEmail: plainTextEmail,
        emailSubject: `[AI Agent] Your ${displayAgentName} results are ready!`,
        meta: { model: 'llama-3.3-70b-versatile', provider: 'Groq' },
        version: '4.0'
    }
}];

